mapper.select:
SELECT th.TRANS_ID AS transId, th.PLANT_CD AS plantCd, th.TRANS_NO AS transNo, th.TRANS_DT AS transDt, th.TRANS_TYPE AS transType, th.TRANS_REASON AS transReason, th.ITEM_CD AS itemCd, th.LOT_NO AS lotNo, th.TRANS_QTY AS transQty, th.UNIT AS unit, th.FROM_WAREHOUSE_CD AS fromWarehouseCd, th.TO_WAREHOUSE_CD AS toWarehouseCd, th.REF_NO AS refNo, th.REG_DTM AS regDtm FROM INV_TRANS_HIS th WHERE 1 = 1
AND th.PLANT_CD = #{plantCd}
AND th.ITEM_CD = #{itemCd}
AND th.TRANS_DT >= #{fromDt}
AND th.TRANS_DT <= #{toDt}
ORDER BY th.TRANS_DT DESC, th.TRANS_ID DESC

SELECT COUNT(*)
FROM INV_TRANS_HIS
WHERE TRANS_DT = #{transDt}
